// ── Service PDF Feuille d'Appel ──────────────────────────────────
// Reproduit exactement le style du pdf_service.dart Flutter
import jsPDF from 'jspdf';
import 'jspdf-autotable';

const CACHET_B64    = '';
const SIGNATURE_B64 = '';

// ── Couleurs LPR ─────────────────────────────────────────────────
const NAVY   = [26, 46, 74];
const BLUE   = [37, 99, 235];
const ORANGE = [232, 73, 15];
const GREY   = [107, 114, 128];
const GREEN  = [22, 163, 74];
const RED    = [220, 38, 38];
const AMBER  = [217, 119, 6];
const WHITE  = [255, 255, 255];
const LIGHT  = [249, 250, 251];

const hex2rgb = (hex) => {
  const r = parseInt(hex.slice(1,3),16);
  const g = parseInt(hex.slice(3,5),16);
  const b = parseInt(hex.slice(5,7),16);
  return [r, g, b];
};

export const generateFeuilleAppelPDF = ({
  classe_nom,
  matiere_nom,
  date_appel,
  enseignant_nom,
  eleves,
}) => {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
  const W = 190; // largeur utile (210 - 2*10)
  const ML = 10; // marge gauche
  const now = new Date();
  const heure = now.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

  const presents = eleves.filter(e => e.statut === 'present').length;
  const absents  = eleves.filter(e => e.statut === 'absent').length;
  const retards  = eleves.filter(e => e.statut === 'retard').length;
  const total    = eleves.length;
  const taux     = total === 0 ? '0%' : Math.round(presents / total * 100) + '%';

  let y = 10;

  // ── EN-TÊTE ───────────────────────────────────────────────────
  doc.setFillColor(...hex2rgb('#FFF0EB'));
  doc.setDrawColor(...hex2rgb('#FFD0B5'));
  doc.setLineWidth(0.5);
  doc.roundedRect(ML, y, W, 22, 3, 3, 'FD');

  doc.setFontSize(14).setTextColor(...ORANGE).setFont('helvetica', 'bold');
  doc.text('LA PORTE DE LA REUSSITE', ML + 6, y + 8);
  doc.setFontSize(9).setTextColor(...NAVY).setFont('helvetica', 'bold');
  doc.text('PREPAS EXAMENS', ML + 6, y + 14);
  doc.setFontSize(7).setTextColor(...GREY).setFont('helvetica', 'italic');
  doc.text('Avec nous la clé du succès est entre vos mains', ML + 6, y + 19);

  // Date en haut à droite
  doc.setFillColor(...hex2rgb('#FFF0EB'));
  doc.setDrawColor(...hex2rgb('#FFD0B5'));
  doc.roundedRect(ML + W - 35, y + 2, 35, 9, 2, 2, 'FD');
  doc.setFontSize(9).setTextColor(...ORANGE).setFont('helvetica', 'bold');
  doc.text(date_appel, ML + W - 33, y + 8);
  doc.setFontSize(7).setTextColor(...GREY).setFont('helvetica', 'normal');
  doc.text(`Heure : ${heure}`, ML + W - 33, y + 17);

  y += 28;

  // ── TITRE ────────────────────────────────────────────────────
  doc.setFillColor(...ORANGE);
  doc.roundedRect(ML, y, W, 12, 3, 3, 'F');
  doc.setFontSize(13).setTextColor(...WHITE).setFont('helvetica', 'bold');
  doc.text('FEUILLE DE PRÉSENCE', ML + W/2, y + 8, { align: 'center' });
  y += 18;

  // ── INFOS SÉANCE ─────────────────────────────────────────────
  doc.setFillColor(...hex2rgb('#EFF6FF'));
  doc.setDrawColor(...BLUE);
  doc.setLineWidth(0.3);
  doc.roundedRect(ML, y, W, 18, 3, 3, 'FD');

  const cols = [0, W/4, W/2, 3*W/4];
  const labels = ['CLASSE', 'MATIÈRE', 'ENSEIGNANT', 'DATE'];
  const values = [classe_nom || '—', matiere_nom || '—', enseignant_nom || '—', date_appel || '—'];

  cols.forEach((cx, i) => {
    doc.setFontSize(7).setTextColor(...BLUE).setFont('helvetica', 'bold');
    doc.text(labels[i], ML + cx + W/8, y + 6, { align: 'center' });
    doc.setFontSize(10).setTextColor(...NAVY).setFont('helvetica', 'bold');
    doc.text(values[i], ML + cx + W/8, y + 14, { align: 'center', maxWidth: W/4 - 2 });
    if (i < 3) {
      doc.setDrawColor(...hex2rgb('#BFDBFE'));
      doc.setLineWidth(0.3);
      doc.line(ML + (i+1)*W/4, y + 3, ML + (i+1)*W/4, y + 15);
    }
  });
  y += 24;

  // ── STATS ────────────────────────────────────────────────────
  const statData = [
    { label: 'TOTAL',    value: String(total),    color: NAVY,  bg: '#EFF6FF', border: BLUE  },
    { label: 'PRÉSENTS', value: String(presents), color: GREEN, bg: '#F0FDF4', border: GREEN },
    { label: 'ABSENTS',  value: String(absents),  color: RED,   bg: '#FEF2F2', border: RED   },
    { label: 'RETARDS',  value: String(retards),  color: AMBER, bg: '#FFFBEB', border: AMBER },
    { label: 'TAUX',     value: taux,             color: GREEN, bg: '#F0FDF4', border: GREEN },
  ];

  const statW = (W - 4*2) / 5;
  statData.forEach((s, i) => {
    const sx = ML + i*(statW + 2);
    doc.setFillColor(...hex2rgb(s.bg));
    doc.setDrawColor(...s.border);
    doc.setLineWidth(0.3);
    doc.roundedRect(sx, y, statW, 16, 2, 2, 'FD');
    doc.setFontSize(14).setTextColor(...s.color).setFont('helvetica', 'bold');
    doc.text(s.value, sx + statW/2, y + 9, { align: 'center' });
    doc.setFontSize(6).setTextColor(...s.color).setFont('helvetica', 'normal');
    doc.text(s.label, sx + statW/2, y + 14, { align: 'center' });
  });
  y += 22;

  // ── TABLEAU ───────────────────────────────────────────────────
  const statutColor = { present: GREEN, absent: RED, retard: AMBER };
  const statutBg    = { present: '#F0FDF4', absent: '#FEF2F2', retard: '#FFFBEB' };
  const statutLabel = { present: 'PRÉSENT', absent: 'ABSENT', retard: 'RETARD' };

  doc.autoTable({
    startY: y,
    margin: { left: ML, right: ML },
    head: [['N°', 'NOM & PRÉNOM', 'STATUT']],
    body: eleves.map((e, i) => [
      String(i + 1),
      `${e.nom?.toUpperCase()} ${e.prenom}`,
      statutLabel[e.statut] || 'PRÉSENT',
    ]),
    columnStyles: {
      0: { cellWidth: 12, halign: 'center' },
      1: { cellWidth: 130, fontStyle: 'bold' },
      2: { cellWidth: 48, halign: 'center', fontStyle: 'bold' },
    },
    headStyles: {
      fillColor: NAVY,
      textColor: WHITE,
      fontSize: 9,
      fontStyle: 'bold',
      cellPadding: 4,
    },
    bodyStyles: {
      fontSize: 10,
      cellPadding: 3,
    },
    alternateRowStyles: { fillColor: LIGHT },
    didDrawCell: (data) => {
      if (data.section === 'body' && data.column.index === 2) {
        const statut = eleves[data.row.index]?.statut || 'present';
        const color = statutColor[statut] || GREY;
        const bg    = statutBg[statut]    || '#F9FAFB';
        const label = statutLabel[statut] || 'PRÉSENT';
        const { x, y: cy, width, height } = data.cell;
        const pad = 2;
        doc.setFillColor(...hex2rgb(bg));
        doc.setDrawColor(...color);
        doc.setLineWidth(0.3);
        doc.roundedRect(x + pad, cy + pad, width - pad*2, height - pad*2, 2, 2, 'FD');
        doc.setFontSize(8).setTextColor(...color).setFont('helvetica', 'bold');
        doc.text(label, x + width/2, cy + height/2 + 1, { align: 'center' });
      }
    },
    tableLineColor: hex2rgb('#E5E7EB'),
    tableLineWidth: 0.3,
  });

  y = doc.lastAutoTable.finalY + 12;

  // ── SIGNATURE + CACHET ────────────────────────────────────────
  if (y > 230) { doc.addPage(); y = 15; }

  // Signature
  doc.setDrawColor(...hex2rgb('#E5E7EB'));
  doc.setLineWidth(0.3);
  doc.rect(ML, y, 90, 38);
  doc.setFontSize(9).setTextColor(...NAVY).setFont('helvetica', 'bold');
  doc.text('Signature du responsable', ML + 5, y + 7);
  doc.setFontSize(7).setTextColor(...GREY).setFont('helvetica', 'italic');
  doc.text('des cours de remise à niveau', ML + 5, y + 12);
  try {
    doc.addImage(SIGNATURE_B64, 'PNG', ML + 5, y + 13, 80, 22);
  } catch (e) {}
  doc.setFontSize(7).setTextColor(...GREY).setFont('helvetica', 'normal');
  doc.text('Signature', ML + 30, y + 36);

  // Cachet
  doc.rect(ML + 100, y, 90, 38);
  doc.setFontSize(9).setTextColor(...NAVY).setFont('helvetica', 'bold');
  doc.text("Cachet de l'établissement", ML + 105, y + 7);
  try {
    doc.addImage(CACHET_B64, 'PNG', ML + 121, y + 10, 28, 28);
  } catch (e) {}

  y += 48;

  // ── PIED DE PAGE ─────────────────────────────────────────────
  doc.setFillColor(...LIGHT);
  doc.roundedRect(ML, y, W, 10, 2, 2, 'F');
  doc.setFontSize(7).setTextColor(...GREY).setFont('helvetica', 'italic');
  doc.text(
    `Document généré par le Système LPR — La Porte de la Réussite — ${date_appel} à ${heure}`,
    ML + W/2, y + 6, { align: 'center' }
  );

  // Télécharger
  const fileName = `presence_${classe_nom}_${matiere_nom}_${date_appel}.pdf`
    .replace(/ /g, '_');
  const pdfBlob = doc.output('blob');
const url = window.URL.createObjectURL(pdfBlob);
const link = document.createElement('a');
link.href = url;
link.download = fileName;
document.body.appendChild(link);
link.click();
document.body.removeChild(link);
window.URL.revokeObjectURL(url);
};